using System;
using System.Collections.Generic;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace Entropic.GUI.Models;

/// <summary>
/// Generates the full standalone HTML page from a list of ChatMessages.
/// Replaces the Python format_html() function.
/// </summary>
public static class HtmlFormatter
{
    /// <summary>Version marker embedded in every generated HTML. Bump when JS changes.</summary>
    public const string VersionMarker = "<!-- cchat-v10 -->";

    /// <summary>Check whether an HTML file was generated by the current HtmlFormatter version.</summary>
    public static bool IsCurrent(string htmlPath)
    {
        try
        {
            // Read just the first 512 bytes — marker is near the top
            using var fs = new System.IO.FileStream(htmlPath, System.IO.FileMode.Open,
                System.IO.FileAccess.Read, System.IO.FileShare.ReadWrite);
            var buf = new byte[512];
            var n = fs.Read(buf, 0, buf.Length);
            return System.Text.Encoding.UTF8.GetString(buf, 0, n).Contains(VersionMarker);
        }
        catch { return false; }
    }

    private static string H(string s) => WebUtility.HtmlEncode(s);

    private static string RoleLabel(ChatMessage msg) => msg.Role switch
    {
        "user" => "User",
        "assistant" => "Claude",
        "subagent_user" => "Agent Prompt",
        "subagent_assistant" => "Agent Response",
        "subagent_start" => "Agent",
        "subagent_end" => "",
        "plan" or "plan_summary" => "Plan",
        "task" or "task_summary" => "Task",
        "cli_session_start" => "CLI Session",
        "cli_session_end" => "",
        _ => msg.Role,
    };

    private static string CssClass(ChatMessage msg)
    {
        if (msg.Cli)
            return msg.Role.Contains("user") ? "msg-cli-user" : "msg-cli-assistant";
        if (msg.Role.Contains("subagent"))
            return "msg-subagent";
        if (msg.Role is "plan" or "plan_summary")
            return "msg-plan";
        if (msg.Role is "task" or "task_summary")
            return "msg-task";
        if (msg.Role.Contains("user"))
            return "msg-user";
        return "msg-assistant";
    }

    public static string FormatHtml(
        List<ChatMessage> messages,
        string title = "",
        bool includeImages = true,
        string repoRemote = "",
        string repoPath = "")
    {
        var genTime = DateTime.UtcNow.ToString("yyyy-MM-dd HH:mm:ss") + " UTC";
        var repoTitle = repoRemote.Length > 0 ? H(repoRemote) : H(title.Length > 0 ? title : "Chat Log");
        var pathLine = repoPath.Length > 0 ? $"<div class='repo-path'>{H(repoPath)}</div>" : "";

        var sb = new StringBuilder(messages.Count * 500);

        sb.AppendLine("<!DOCTYPE html>").AppendLine(VersionMarker);
        sb.Append("<html><head><meta charset='utf-8'><title>").Append(H(title.Length > 0 ? title : "Chat Log")).AppendLine("</title>");
        sb.AppendLine(Css);
        sb.AppendLine("</head><body>");

        // Titlebar — single row matching AXAML toolbar
        sb.Append("<div id='titlebar'>");
        sb.Append("<span class='title-name'>").Append(repoTitle).Append("</span>");
        if (repoPath.Length > 0)
            sb.Append("<span class='repo-path'>").Append(H(repoPath)).Append("</span>");
        sb.Append("<span class='gen-time'>").Append(genTime).Append("</span>");
        sb.Append("<span class='spacer'></span>");
        sb.Append("<div class='controls'>");
        sb.Append("<input type='text' id='search-box' placeholder='Search...' oninput='doSearch(this.value)' />");
        sb.Append("<div class='filters'>");
        sb.Append("<label><input type='checkbox' id='flt-cli' onchange='toggleFilter(\"cli\",this.checked)'>CLI</label>");
        sb.Append("<label><input type='checkbox' id='flt-plans' checked onchange='toggleFilter(\"plans\",this.checked)'>Plans</label>");
        sb.Append("<label><input type='checkbox' id='flt-tasks' checked onchange='toggleFilter(\"tasks\",this.checked)'>Tasks</label>");
        sb.Append("<label><input type='checkbox' id='flt-subagents' checked onchange='toggleFilter(\"subagents\",this.checked)'>Subagents</label>");
        sb.Append("</div>");
        sb.Append("<span style='font-size:10px;color:var(--fg-dim);margin:0 3px 0 0'>Last</span>");
        sb.Append("<input type='number' id='msg-limit' value='200' min='1' style='width:52px;background:var(--search-bg);border:1px solid var(--search-border);border-radius:4px;padding:0 3px;font-size:10px;color:var(--fg);text-align:center;height:22px;box-sizing:border-box' title='Number of messages to show (from most recent)' onchange='applyMessageLimit(this.value)'/>");
        sb.Append("<span id='msg-limit-label' style='font-size:9px;color:var(--fg-dim);margin:0 0 0 4px'></span>");
        sb.Append("<span class='sep'></span>");
        sb.Append("<button class='tb-btn' onclick='toggleCollapse()' id='collapse-btn' title='Collapse/expand Claude responses'>&#9776;</button>");
        sb.Append("<button class='tb-btn' onclick='toggleTheme()' id='theme-btn' title='Toggle light/dark theme'>&#x2600;</button>");
        sb.Append("<div id='prompt-nav'>");
        sb.Append("<button onclick='navPrompt(-1)' title='Previous prompt (Alt+Up)'>&#9650;</button>");
        sb.Append("<span class='counter' id='nav-counter'>- / -</span>");
        sb.Append("<button onclick='navPrompt(1)' title='Next prompt (Alt+Down)'>&#9660;</button>");
        sb.Append("</div>");
        sb.Append("<span class='sep'></span>");
        sb.Append("<button class='tb-btn' onclick='copyConversation(\"md\")' title='Copy as Markdown'>&#x29C9;<small>md</small></button>");
        sb.Append("<button class='tb-btn' onclick='copyConversation(\"text\")' title='Copy as plain text'>&#x29C9;<small>txt</small></button>");
        sb.Append("<button class='tb-btn' onclick='copyConversation(\"html\")' title='Copy as HTML'>&#x29C9;<small>htm</small></button>");
        sb.Append("<span class='sep'></span>");
        sb.Append("<button class='tb-btn' onclick='saveConversation(\"md\")' title='Save as Markdown'>&#x2913;<small>md</small></button>");
        sb.Append("<button class='tb-btn' onclick='saveConversation(\"text\")' title='Save as plain text'>&#x2913;<small>txt</small></button>");
        sb.Append("<button class='tb-btn' onclick='saveConversation(\"html\")' title='Save as HTML'>&#x2913;<small>htm</small></button>");
        sb.Append("<span class='sep'></span>");
        sb.Append("<button class='tb-btn' id='screenshot-btn' title='Screenshot'>&#x1F4F7;</button>");
        sb.Append("<label class='follow-label'><input type='checkbox' id='follow-chk' onchange='toggleFollow(this.checked)'>Follow</label>");
        sb.Append("</div></div>");

        // Content area: timeline on left, messages on right
        sb.AppendLine("<div id='content-area'>");
        sb.AppendLine("<div id='timeline'></div>");
        sb.AppendLine("<div id='messages'>");

        // Messages
        var openDetails = 0;
        var msgIdx = 0;
        string? prevGroupKey = null;
        var bubbleOpen = false;

        void CloseBubble()
        {
            if (bubbleOpen)
            {
                sb.Append("</div>");
                bubbleOpen = false;
            }
            prevGroupKey = null;
        }

        foreach (var msg in messages)
        {
            var ts = msg.Timestamp ?? "";
            var tsShort = ts.Length >= 19 ? ts[..19] : ts;
            var tsHtml = ts.Length > 0 ? $"<span class='timestamp'>{H(tsShort)}</span>" : "";
            var tsAttr = ts.Length > 0 ? H(tsShort) : "";

            if (msg.Role == "subagent_start")
            {
                CloseBubble();
                sb.Append($"<details open data-role='subagent_start'><summary>{tsHtml}{H(msg.Text)}</summary><div class='inner'>");
                openDetails++;
                continue;
            }
            if (msg.Role == "subagent_end")
            {
                CloseBubble();
                if (openDetails > 0) { sb.Append("</div></details>"); openDetails--; }
                continue;
            }
            if (msg.Role == "cli_session_start")
            {
                CloseBubble();
                sb.Append($"<details data-role='cli_session_start'><summary class='msg msg-cli'>{tsHtml}{H(msg.Text)}</summary><div class='inner'>");
                openDetails++;
                continue;
            }
            if (msg.Role == "cli_session_end")
            {
                CloseBubble();
                if (openDetails > 0) { sb.Append("</div></details>"); openDetails--; }
                continue;
            }

            var label = RoleLabel(msg);
            var cssClass = CssClass(msg);
            var cliBadge = msg.Cli ? "<span class='cli-badge'>CLI</span>" : "";
            var textHtml = MarkdownToHtml(msg.Text);

            // Inline images
            if (includeImages && msg.Images is not null)
            {
                for (var i = 0; i < msg.Images.Count; i++)
                {
                    var img = msg.Images[i];
                    var imgTag = $"<img src='data:{img.MediaType};base64,{img.Data}' style='max-width:100%;border-radius:6px;margin:8px 0;'>";
                    textHtml = textHtml.Replace($"\x00IMG{i}\x00", imgTag);
                }
            }
            else
            {
                textHtml = Regex.Replace(textHtml, @"\x00IMG\d+\x00", "");
            }

            var rawTextAttr = H(msg.Text).Replace("'", "&#39;").Replace("\n", "&#10;");
            var groupKey = cssClass;
            var isContinuation = groupKey == prevGroupKey && bubbleOpen;

            if (isContinuation)
            {
                sb.Append($"<div class='msg-cont' id='msg-{msgIdx}' data-role='{msg.Role}' data-ts='{tsAttr}' data-text='{rawTextAttr}'>");
                sb.Append(CopyBarHtml);
                sb.Append($"<div class='cont-ts'>{tsHtml}</div>");
                sb.Append($"<div class='content'>{textHtml}</div>");
                sb.Append("</div>");
            }
            else
            {
                CloseBubble();
                sb.Append($"<div class='msg {cssClass}' id='msg-{msgIdx}' data-role='{msg.Role}' data-ts='{tsAttr}' data-text='{rawTextAttr}'>");
                sb.Append(CopyBarHtml);
                sb.Append($"<div class='role'>{H(label)}{cliBadge} {tsHtml}</div>");
                sb.Append($"<div class='content'>{textHtml}</div>");
                bubbleOpen = true;
                prevGroupKey = groupKey;
            }

            msgIdx++;
        }

        CloseBubble();
        for (var i = 0; i < openDetails; i++)
            sb.Append("</div></details>");

        sb.AppendLine("</div></div>"); // close #messages and #content-area
        sb.AppendLine(Script);
        sb.AppendLine("</body></html>");
        return sb.ToString();
    }

    // -----------------------------------------------------------------------
    // Markdown -> HTML (minimal: code blocks, inline code, bold, paragraphs)
    // -----------------------------------------------------------------------

    private static readonly Regex CodeBlockRe = new(
        @"```(\w*)\n(.*?)```", RegexOptions.Singleline | RegexOptions.Compiled);

    public static string MarkdownToHtml(string text)
    {
        var codeBlocks = new List<string>();

        text = CodeBlockRe.Replace(text, m =>
        {
            var lang = m.Groups[1].Value;
            var code = m.Groups[2].Value.Trim();
            var highlighted = HighlightCode(code, lang);
            var idx = codeBlocks.Count;
            codeBlocks.Add($"<pre><code>{highlighted}</code></pre>");
            return $"\x00CODE{idx}\x00";
        });

        // HTML-escape prose (code blocks already handled)
        text = H(text);

        // Split into paragraphs
        var paragraphs = Regex.Split(text, @"\n{2,}");
        var htmlParts = new List<string>();

        foreach (var rawPara in paragraphs)
        {
            var para = rawPara.Trim();
            if (para.Length == 0) continue;
            if (Regex.IsMatch(para, @"^\x00CODE\d+\x00$"))
            {
                htmlParts.Add(para);
                continue;
            }
            var lines = para.Split('\n');
            var formatted = new List<string>();
            foreach (var line in lines)
            {
                var l = Regex.Replace(line, @"`([^`]+)`", "<code>$1</code>");
                l = Regex.Replace(l, @"\*\*(.+?)\*\*", "<strong>$1</strong>");
                formatted.Add(l);
            }
            htmlParts.Add($"<p>{string.Join("<br>", formatted)}</p>");
        }

        text = string.Join("\n", htmlParts);

        // Restore code blocks
        for (var i = 0; i < codeBlocks.Count; i++)
            text = text.Replace($"\x00CODE{i}\x00", codeBlocks[i]);

        return text;
    }

    // -----------------------------------------------------------------------
    // Basic syntax highlighting
    // -----------------------------------------------------------------------

    private static readonly Regex CommentSlashRe = new(
        @"(//.*?)$", RegexOptions.Multiline | RegexOptions.Compiled);
    private static readonly Regex CommentHashRe = new(
        @"(#.*?)$", RegexOptions.Multiline | RegexOptions.Compiled);
    private static readonly Regex StringDquoteRe = new(
        @"(&quot;)(.*?)(&quot;)", RegexOptions.Compiled);
    private static readonly Regex StringSquoteRe = new(
        @"(&#x27;)(.*?)(&#x27;)", RegexOptions.Compiled);
    private static readonly Regex NumberRe = new(
        @"\b(\d+\.?\d*)\b", RegexOptions.Compiled);
    private static readonly Regex KeywordRe = new(
        @"\b(def|class|if|elif|else|for|while|return|import|from|in|not|and|or|is|None|True|False" +
        @"|function|const|let|var|async|await|try|catch|except|finally|raise|yield" +
        @"|public|private|static|void|int|string|bool|new|this|self|null|undefined" +
        @"|sub|my|use|require|our|local)\b", RegexOptions.Compiled);

    public static string HighlightCode(string code, string lang)
    {
        code = H(code);
        code = CommentSlashRe.Replace(code, "<span class=\"cmt\">$1</span>");
        code = CommentHashRe.Replace(code, "<span class=\"cmt\">$1</span>");
        code = StringDquoteRe.Replace(code, "<span class=\"str\">$1$2$3</span>");
        code = StringSquoteRe.Replace(code, "<span class=\"str\">$1$2$3</span>");
        code = NumberRe.Replace(code, "<span class=\"num\">$1</span>");
        code = KeywordRe.Replace(code, "<span class=\"kw\">$1</span>");
        return code;
    }

