    private const string CopyBarHtml =
        "<div class='copy-bar'>" +
        "<button onclick='copyMsg(this,\"text\")' title='Copy Plain Text'>T</button>" +
        "<button onclick='copyMsg(this,\"md\")' title='Copy Markdown'>M</button>" +
        "<button onclick='copyMsg(this,\"html\")' title='Copy HTML'>&lt;/&gt;</button>" +
        "<button onclick='copyMsg(this,\"rich\")' title='Copy Rich Text'>R</button>" +
        "</div>";

