        body.hide-subagents details[data-role=""subagent_start""] { display: none; }
        body.hide-subagents .msg-subagent { display: none; }
        .msg.prompt-highlight { outline: 3px solid #4a90d9; outline-offset: 2px; transition: outline-color 0.3s; }
        mark.search-hit { background: var(--highlight-bg); color: inherit; border-radius: 2px; padding: 0 1px; }
        body.search-active .msg:not(.search-match) { opacity: 0.2; transition: opacity 0.15s; }
        .msg-cont { position: relative; padding: 4px 0 0 0;
                    border-top: 1px solid var(--asst-border); margin-top: 8px; }
        .cont-ts { font-size: 0.72em; color: var(--fg-dim); text-align: right; margin-bottom: 2px; }
        .msg-cont:hover > .copy-bar { display: flex; }
        .msg-assistant .content.collapsed { max-height: 120px; overflow: hidden;
            -webkit-mask-image: linear-gradient(to bottom, black 60%, transparent 100%);
            mask-image: linear-gradient(to bottom, black 60%, transparent 100%); }
        .collapse-toggle { font-size: 0.75em; color: var(--fg-dim); cursor: pointer;
            border: none; background: none; padding: 2px 0; margin-top: 4px; }
        .collapse-toggle:hover { color: var(--fg-muted); text-decoration: underline; }
    </style>";

    private const string Script = @"
    <script>
    (function(){
      var savedTheme = localStorage.getItem('cchat-theme') || 'light';
      if (savedTheme === 'dark') document.documentElement.setAttribute('data-theme','dark');

      function toggleTheme() {
        var isDark = document.documentElement.getAttribute('data-theme') === 'dark';
        document.documentElement.setAttribute('data-theme', isDark ? 'light' : 'dark');
        localStorage.setItem('cchat-theme', isDark ? 'light' : 'dark');
      }
      window.toggleTheme = toggleTheme;

      function toggleFilter(kind, checked) {
        document.body.classList.toggle('hide-' + kind, !checked);
        rebuildTimeline();
      }
      window.toggleFilter = toggleFilter;
      document.body.classList.add('hide-cli');

      function applyMessageLimit(val) {
        var limit = parseInt(val, 10);
        if (isNaN(limit) || limit < 1) return;
        var allMsgs = Array.from(document.querySelectorAll('.msg, .msg-cont'));
        var total = allMsgs.length;
        var hide = Math.max(0, total - limit);
        allMsgs.forEach(function(el, i) { el.style.display = i < hide ? 'none' : ''; });
        var label = document.getElementById('msg-limit-label');
        if (label) label.textContent = 'of ' + total;
        rebuildTimeline();
      }
      window.applyMessageLimit = applyMessageLimit;
      setTimeout(function() { applyMessageLimit(200); }, 100);

      var promptIdx = -1;
      var _navLock = 0; // when >0, scroll handler won't override promptIdx
      function getVisiblePrompts() {
        return Array.from(document.querySelectorAll('.msg[data-role=""user""]'))
          .filter(function(el) { return el.offsetParent !== null; });
      }
      function updateCounter(prompts) {
        var el = document.getElementById('nav-counter');
        if (prompts.length === 0) { el.textContent = '- / -'; return; }
        el.textContent = (promptIdx + 1) + ' / ' + prompts.length;
      }
      function navPrompt(dir) {
        var prompts = getVisiblePrompts();
        console.log('[navPrompt] dir=' + dir + ' promptIdx=' + promptIdx + ' prompts=' + prompts.length + ' _navLock=' + _navLock);
        if (prompts.length === 0) return;
        _navLock++;
        document.querySelectorAll('.prompt-highlight').forEach(function(el) { el.classList.remove('prompt-highlight'); });
        promptIdx = Math.max(0, Math.min(prompts.length - 1, promptIdx + dir));
        prompts[promptIdx].scrollIntoView({behavior:'instant', block:'start'});
        prompts[promptIdx].classList.add('prompt-highlight');
        updateCounter(prompts);
        updateActiveMarker();
        console.log('[navPrompt] after: promptIdx=' + promptIdx);
        setTimeout(function() { _navLock--; console.log('[navPrompt] unlock, _navLock=' + _navLock); }, 100);
      }
      window.navPrompt = navPrompt;

      function navToFirst() {
        var prompts = getVisiblePrompts();
        console.log('[navToFirst] prompts=' + prompts.length + ' _navLock=' + _navLock);
        if (prompts.length === 0) return;
        _navLock++;
        promptIdx = 0;
        prompts[0].scrollIntoView({behavior:'instant', block:'start'});
        prompts[0].classList.add('prompt-highlight');
        updateCounter(prompts);
        updateActiveMarker();
        setTimeout(function() { _navLock--; console.log('[navToFirst] unlock'); }, 300);
      }
      window.navToFirst = navToFirst;
      function navToLast() {
        var prompts = getVisiblePrompts();
        console.log('[navToLast] prompts=' + prompts.length + ' _navLock=' + _navLock);
        if (prompts.length === 0) return;
        _navLock++;
        promptIdx = prompts.length - 1;
        prompts[promptIdx].scrollIntoView({behavior:'instant', block:'start'});
        prompts[promptIdx].classList.add('prompt-highlight');
        updateCounter(prompts);
        updateActiveMarker();
        console.log('[navToLast] set promptIdx=' + promptIdx);
        setTimeout(function() { _navLock--; console.log('[navToLast] unlock'); }, 300);
      }
      window.navToLast = navToLast;

      var bubbleIdx = -1;
      function navBubble(dir) {
        var msgs = Array.from(document.querySelectorAll('.msg'))
          .filter(function(el) { return el.offsetParent !== null; });
        if (msgs.length === 0) return;
        bubbleIdx = Math.max(0, Math.min(msgs.length - 1, bubbleIdx + dir));
        msgs[bubbleIdx].scrollIntoView({behavior:'smooth', block:'start'});
      }
      window.navBubble = navBubble;

      document.addEventListener('keydown', function(e) {
        if (e.altKey && e.key === 'ArrowUp') { e.preventDefault(); navPrompt(-1); }
        if (e.altKey && e.key === 'ArrowDown') { e.preventDefault(); navPrompt(1); }
        if (e.shiftKey && e.key === 'ArrowUp') { e.preventDefault(); navPrompt(-1); }
        if (e.shiftKey && e.key === 'ArrowDown') { e.preventDefault(); navPrompt(1); }
        if (!e.altKey && !e.shiftKey && !e.ctrlKey && !e.metaKey && e.key === 'ArrowUp') { e.preventDefault(); navBubble(-1); }
        if (!e.altKey && !e.shiftKey && !e.ctrlKey && !e.metaKey && e.key === 'ArrowDown') { e.preventDefault(); navBubble(1); }
        if ((e.ctrlKey || e.metaKey) && e.key === 'f') { e.preventDefault(); document.getElementById('search-box').focus(); }
      });

      function copyMsg(btn, mode) {
        var msgEl = btn.closest('.msg-cont') || btn.closest('.msg');
        if (!msgEl) return;
        var text = msgEl.dataset.text || '';
        var contentEl = msgEl.querySelector('.content');
        var html = contentEl ? contentEl.innerHTML : '';
        var done = function() {
          btn.classList.add('copied'); var orig = btn.textContent;
          btn.textContent = 'OK';
          setTimeout(function() { btn.classList.remove('copied'); btn.textContent = orig; }, 800);
        };
        if (mode === 'text') {
          var plain = text.replace(/\*\*(.+?)\*\*/g, '$1').replace(/`([^`]+)`/g, '$1');
          navigator.clipboard.writeText(plain).then(done);
        } else if (mode === 'md') {
          navigator.clipboard.writeText(text).then(done);
        } else if (mode === 'html') {
          var blob = new Blob([html], {type: 'text/html'});
          navigator.clipboard.write([new ClipboardItem({'text/html': blob})]).then(done);
        } else if (mode === 'rich') {
          var htmlBlob = new Blob([html], {type: 'text/html'});
          var textBlob = new Blob([text], {type: 'text/plain'});
          navigator.clipboard.write([new ClipboardItem({'text/html': htmlBlob, 'text/plain': textBlob})]).then(done);
        }
      }
      window.copyMsg = copyMsg;

      function getVisibleMessages() {
        return Array.from(document.querySelectorAll('.msg'))
          .filter(function(el) { return el.offsetParent !== null; });
      }
      function formatConversation(mode) {
        var msgs = getVisibleMessages();
        var title = document.querySelector('#titlebar h1');
        var titleText = title ? title.textContent : 'Conversation';
        var lines = [];
        if (mode === 'md') {
          lines.push('# ' + titleText + '\n');
          msgs.forEach(function(el) {
            var label = el.querySelector('.role') ? el.querySelector('.role').textContent : el.dataset.role || 'unknown';
            var text = el.dataset.text || el.querySelector('.content')?.textContent || '';
            lines.push('## ' + label + '\n'); lines.push(text + '\n'); lines.push('---\n');
          });
        } else if (mode === 'text') {
          lines.push(titleText + '\n');
          msgs.forEach(function(el) {
            var label = el.querySelector('.role') ? el.querySelector('.role').textContent : el.dataset.role || 'unknown';
            var text = el.dataset.text || el.querySelector('.content')?.textContent || '';
            lines.push('[' + label + ']'); lines.push(text + '\n');
          });
        } else if (mode === 'html') {
          var htmlParts = msgs.map(function(el) { return el.outerHTML; });
          return '<!DOCTYPE html><html><head><meta charset=""utf-8""></head><body>' + htmlParts.join('\n') + '</body></html>';
        }
        return lines.join('\n');
      }
      function copyConversation(mode) {
        var text = formatConversation(mode);
        if (mode === 'html') {
          var blob = new Blob([text], {type: 'text/html'});
          navigator.clipboard.write([new ClipboardItem({'text/html': blob})]);
        } else { navigator.clipboard.writeText(text); }
      }
      window.copyConversation = copyConversation;
      function saveConversation(mode) {
        var text = formatConversation(mode);
        var ext = mode === 'md' ? '.md' : mode === 'html' ? '.html' : '.txt';
        var mime = mode === 'html' ? 'text/html' : 'text/plain';
        var blob = new Blob([text], {type: mime});
        var a = document.createElement('a'); a.href = URL.createObjectURL(blob);
        a.download = 'conversation' + ext; a.click(); URL.revokeObjectURL(a.href);
      }
      window.saveConversation = saveConversation;

      var allCollapsed = false;
      function toggleCollapse() {
        allCollapsed = !allCollapsed;
        document.querySelectorAll('.msg-assistant .content').forEach(function(el) { el.classList.toggle('collapsed', allCollapsed); });
        document.querySelectorAll('.collapse-toggle').forEach(function(btn) { btn.textContent = allCollapsed ? 'Show more' : 'Show less'; });
      }
      window.toggleCollapse = toggleCollapse;
      document.addEventListener('click', function(e) {
        if (e.target.classList.contains('collapse-toggle')) {
          var content = e.target.previousElementSibling;
          if (!content) return;
          var isCollapsed = content.classList.toggle('collapsed');
          e.target.textContent = isCollapsed ? 'Show more' : 'Show less';
        }
      });
      setTimeout(function() {
        document.querySelectorAll('.msg-assistant .content').forEach(function(el) {
          if (el.scrollHeight > 200) {
            var btn = document.createElement('button'); btn.className = 'collapse-toggle';
            btn.textContent = 'Show less'; el.parentNode.insertBefore(btn, el.nextSibling);
          }
        });
      }, 50);

      var searchTimer;
      function doSearch(query) { clearTimeout(searchTimer); searchTimer = setTimeout(function() { executeSearch(query); }, 150); }
      window.doSearch = doSearch;
      function executeSearch(query) {
        document.querySelectorAll('mark.search-hit').forEach(function(m) { m.replaceWith(m.textContent); });
        document.querySelectorAll('.msg .content').forEach(function(el) { el.normalize(); });
        document.querySelectorAll('.search-match').forEach(function(el) { el.classList.remove('search-match'); });
        if (!query || query.length < 2) { document.body.classList.remove('search-active'); return; }
        document.body.classList.add('search-active');
        var re = new RegExp('(' + query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi');
        document.querySelectorAll('.msg .content').forEach(function(contentEl) {
          var container = contentEl.closest('.msg-cont') || contentEl.closest('.msg');
          var msgEl = contentEl.closest('.msg');
          var rawText = container.dataset.text || '';
          if (!re.test(rawText)) return;
          re.lastIndex = 0;
          msgEl.classList.add('search-match');
          highlightTextNodes(contentEl, re);
        });
      }
      function highlightTextNodes(el, re) {
        var walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT, {
          acceptNode: function(node) {
            if (node.parentNode.closest('pre,code')) return NodeFilter.FILTER_REJECT;
            return NodeFilter.FILTER_ACCEPT;
          }
        });
        var nodes = []; while (walker.nextNode()) nodes.push(walker.currentNode);
        nodes.forEach(function(textNode) {
          var text = textNode.textContent; if (!re.test(text)) return; re.lastIndex = 0;
          var frag = document.createDocumentFragment(); var lastIdx = 0; var match;
          while ((match = re.exec(text)) !== null) {
            if (match.index > lastIdx) frag.appendChild(document.createTextNode(text.slice(lastIdx, match.index)));
            var mark = document.createElement('mark'); mark.className = 'search-hit';
            mark.textContent = match[1]; frag.appendChild(mark); lastIdx = re.lastIndex;
          }
          if (lastIdx < text.length) frag.appendChild(document.createTextNode(text.slice(lastIdx)));
          textNode.parentNode.replaceChild(frag, textNode);
        });
      }

      var timelineEl = document.getElementById('timeline');
      var messagesEl = document.getElementById('messages');
      var tooltipEl = document.createElement('div');
      tooltipEl.className = 'tl-tooltip';
      if (timelineEl) timelineEl.appendChild(tooltipEl);
      function rebuildTimeline() {
        if (!timelineEl) return;
        Array.from(timelineEl.querySelectorAll('.marker')).forEach(function(m) { m.remove(); });
        var prompts = getVisiblePrompts();
        if (prompts.length === 0) return;
        var h = timelineEl.clientHeight;
        prompts.forEach(function(el, i) {
          var marker = document.createElement('div');
          marker.className = 'marker marker-user';
          marker.style.top = Math.round((i / prompts.length) * (h - 8)) + 'px';
          var rawText = el.dataset.text || '';
          var preview = rawText.substring(0, 200);
          if (rawText.length > 200) preview += '...';
          marker.dataset.preview = (el.dataset.ts || '') + '\n' + preview;
          marker.onmouseenter = function(e) {
            tooltipEl.textContent = marker.dataset.preview;
            var rect = marker.getBoundingClientRect();
            tooltipEl.style.top = rect.top + 'px'; tooltipEl.style.display = 'block';
          };
          marker.onmouseleave = function() { tooltipEl.style.display = 'none'; };
          marker.onclick = function() {
            _navLock++;
            promptIdx = i;
            console.log('[marker.click] i=' + i + ' promptIdx=' + promptIdx + ' total=' + prompts.length);
            document.querySelectorAll('.prompt-highlight').forEach(function(el) { el.classList.remove('prompt-highlight'); });
            el.scrollIntoView({behavior:'instant', block:'start'});
            el.classList.add('prompt-highlight');
            updateCounter(prompts); updateActiveMarker();
            setTimeout(function() { _navLock--; console.log('[marker.click] unlock'); }, 100);
          };
          timelineEl.appendChild(marker);
        });
        updateCounter(getVisiblePrompts());
      }
      function updateActiveMarker() {
        var markers = timelineEl.querySelectorAll('.marker');
        markers.forEach(function(m, i) { m.classList.toggle('active', i === promptIdx); });
      }
      (messagesEl || window).addEventListener('scroll', function() {
        requestAnimationFrame(function() {
          if (_navLock > 0) { console.log('[scroll] BLOCKED by _navLock=' + _navLock); return; }
          var prompts = getVisiblePrompts();
          if (prompts.length === 0) return;
          var best;
          var ct = messagesEl || document.documentElement;
          var scrollTop = ct.scrollTop;
          var scrollH = ct.scrollHeight;
          var clientH = ct.clientHeight;
          if (scrollTop <= 5) { best = 0; }
          else if (scrollTop + clientH >= scrollH - 20) { best = prompts.length - 1; }
          else {
            var viewTop = scrollTop + 100; best = 0;
            for (var i = 0; i < prompts.length; i++) { if (prompts[i].offsetTop <= viewTop) best = i; }
          }
          if (best !== promptIdx) {
            console.log('[scroll] override promptIdx ' + promptIdx + ' -> ' + best);
            promptIdx = best; updateCounter(prompts); updateActiveMarker();
          }
        });
      });
      var _followMode = false;
      function toggleFollow(on) {
        _followMode = on;
        if (on) {
          var m = messagesEl || document.documentElement;
          m.scrollTop = m.scrollHeight;
        }
      }
      window.toggleFollow = toggleFollow;

      // Auto-scroll when follow is on and content may have changed
      if (messagesEl) {
        new MutationObserver(function() {
          if (_followMode) messagesEl.scrollTop = messagesEl.scrollHeight;
        }).observe(messagesEl, {childList: true, subtree: true});
      }

      window.addEventListener('resize', rebuildTimeline);

      // On initial load, scroll to last message and select last marker
      setTimeout(function() {
        rebuildTimeline();
        navToLast();
      }, 200);
    })();
    </script>";
}
